    <script>
        $(document).ready(function() {
            "use strict";
            $('.s-highlight').each(function() {
                var $heading = $(this);
                var text = $heading.text().trim();
                var words = text.split(' ');
                var sBreakValue = parseInt($heading.data('s-break')) || 0;
                var sLengthValue = parseInt($heading.data('s-length')) || 1;

                var totalWords = words.length;
                var startIndex = (sBreakValue < 0) ? Math.max(0, totalWords + sBreakValue) : sBreakValue;
                var endIndex = Math.min(totalWords, startIndex + sLengthValue);

                var coloredText = words.map(function(word, index) {
                    if (index >= startIndex && index < endIndex) {
                        return '<span class="text--base">' + word + '</span>';
                    }
                    return word;
                }).join(' ');

                $heading.html(coloredText);
            });
        });
    </script>
<script src="https://accounts.google.com/gsi/client" async defer></script>
<script>
    let googleToken = null;

    function googleLoginResponse(response) {
        googleToken = response.credential;
        $('#typeModalCenter').modal('show');
    }

    document.addEventListener('DOMContentLoaded', function() {
        const continueBtn = document.getElementById('continueLogin');
        const originalBtnHtml = continueBtn.innerHTML;
        const options = document.querySelectorAll('.type-option');

        const preChecked = document.querySelector('input[name="userType"]:checked');
        if (preChecked) {
            const parent = preChecked.closest('.type-option');
            if (parent) parent.classList.add('active');
        }

        options.forEach(option => {
            option.addEventListener('click', (e) => {
                const input = option.querySelector('input[name="userType"]');
                if (input) {
                    input.checked = true;
                }

                options.forEach(opt => opt.classList.remove('active'));
                option.classList.add('active');
            });

            const input = option.querySelector('input[name="userType"]');
            if (input) {
                input.addEventListener('change', () => {
                    if (input.checked) {
                        options.forEach(opt => opt.classList.remove('active'));
                        option.classList.add('active');
                    }
                });
            }
        });

        continueBtn.addEventListener('click', function() {
            const selectedInput = document.querySelector('input[name="userType"]:checked');
            const type = selectedInput ? selectedInput.value : null;

            if (!type) {
                notify('error', 'Please select an account type');
                return;
            }

            if (!googleToken) {
                notify('error', 'Google token missing, please try again');
                return;
            }

            const routeTemplate = "social-login/:type";
            const routeUrl = routeTemplate.replace(':type', type);

            continueBtn.disabled = true;
            continueBtn.innerHTML = `<i class="fas fa-spinner fa-spin me-2"></i> Loading...`;

            fetch(routeUrl, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-CSRF-TOKEN': "wN09QRPixiHjDIJejjUsj1UVuiXpeDcUKHqUadjN"
                    },
                    credentials: 'include',
                    body: JSON.stringify({
                        token: googleToken
                    })
                })
                .then(response => response.json())
                .then(data => {
                    if (data.status === 'success') {
                        window.location.href = data.data.redirect_url ?? '/';
                    } else {
                        notify('error', 'Login error');
                        console.error(data);
                    }
                })
                .catch(err => {
                    console.error(err);
                    notify('error', 'An error occurred during login');
                })
                .finally(() => {
                    setTimeout(() => {
                        continueBtn.disabled = false;
                        continueBtn.innerHTML = originalBtnHtml;
                    }, 300);
                });
        });
    });
</script>

